    1: "LLM memorization generalization",
    2: "catastrophic forgetting language models",
    3: "data efficiency large language models",
    4: "training data memorization neural networks",
    5: "curriculum learning forgetting LLM",
    6: "deduplication training data language models",
    7: "example forgetting machine learning",
    8: "memorization overfitting transformers",
    9: "continual learning language models",
    10: "sample efficiency deep learning forgetting"
}

all_papers = {}
query_results = {}

for i in range(1, 11):
    filepath = f'/tmp/ss_q{i}.json'
    if not os.path.exists(filepath):
        query_results[i] = {"query": query_labels[i], "status": "file_not_found", "count": 0, "paper_ids": []}
        continue

    with open(filepath) as f:
        raw = f.read()

    try:
        data = json.loads(raw)
    except json.JSONDecodeError:
        query_results[i] = {"query": query_labels[i], "status": "parse_error", "count": 0, "paper_ids": []}
        continue

    if 'code' in data and data['code'] == '429':
        query_results[i] = {"query": query_labels[i], "status": "rate_limited_429", "count": 0, "paper_ids": []}
        continue

    papers = data.get('data', [])
    paper_ids = []

    for p in papers:
        pid = p.get('paperId', '')
        if not pid:
            continue
        paper_ids.append(pid)
        if pid not in all_papers:
            all_papers[pid] = {
                "paperId": pid,
                "title": p.get('title', ''),
                "authors": [a.get('name', '') for a in p.get('authors', [])],
                "year": p.get('year'),
                "abstract": p.get('abstract', ''),
                "externalIds": p.get('externalIds', {}),
                "citationCount": p.get('citationCount'),
                "url": p.get('url', ''),
                "arxivId": p.get('externalIds', {}).get('ArXiv', None),
                "source_queries": [query_labels[i]]
            }
        else:
            if query_labels[i] not in all_papers[pid]['source_queries']:
                all_papers[pid]['source_queries'].append(query_labels[i])

    query_results[i] = {
        "query": query_labels[i],
        "status": "success",
        "total_available": data.get('total', 0),
        "count": len(papers),
        "paper_ids": paper_ids
    }

output = {
    "metadata": {
        "source": "Semantic Scholar API",
        "api_endpoint": "https://api.semanticscholar.org/graph/v1/paper/search",
