print(f"File size: {os.path.getsize(outpath)} bytes")

# Print sample titles
print("\nSample papers:")
for p in list(all_papers.values())[:10]:
    print(f"  [{p['year']}] {p['title'][:80]} (cit: {p['citationCount']})")
